def _check_no_gambling(text: str) -> list[str]:
    return [t for t in GAMBLING_TERMS if t in text]


def validate_seeds() -> dict[str, list[str]]:
    """Validate all seed dicts; return errors by section."""
    errors: dict[str, list[str]] = {}
    sections: list[tuple[str, dict[str, list[FAQ]], int]] = [
        ("DISCIPLINE_SEEDS", DISCIPLINE_SEEDS, 50),
        ("CULTURE_SEEDS", CULTURE_SEEDS, 50),
        ("HEALTH_TRAINING_SEEDS", HEALTH_TRAINING_SEEDS, 50),
        ("VENUES_TECH_SEEDS", VENUES_TECH_SEEDS, 50),
        ("WOMENS_WC_SEEDS", WOMENS_WC_SEEDS, 50),
    ]
    for name, data, expected in sections:
        sec_err: list[str] = []
        for cat, faqs in data.items():
            if len(faqs) != expected:
                sec_err.append(f"{cat}: expected {expected} FAQs, got {len(faqs)}")
            questions = [f[0] for f in faqs]
            if len(questions) != len(set(questions)):
                sec_err.append(f"{cat}: duplicate questions")
            for i, f in enumerate(faqs):
                q, alias, short, detail, keywords = f
                if len(short) > 120:
                    sec_err.append(f"{cat}[{i}]: answer_short > 120 chars ({len(short)})")
                kws = [k.strip() for k in keywords.split(",") if k.strip()]
                if len(kws) < 3:
                    sec_err.append(f"{cat}[{i}]: keywords need >=3 items")
                for field_name, val in [("q", q), ("short", short), ("detail", detail), ("kw", keywords)]:
                    bad = _check_no_gambling(val)
                    if bad:
                        sec_err.append(f"{cat}[{i}] {field_name}: gambling term {bad}")
        if sec_err:
            errors[name] = sec_err

    rec_err: list[str] = []
    for cat, faqs in EXTRA_RECORDS.items():
        exp = 50 if cat == "补遗统计" else 45
        if len(faqs) != exp:
            rec_err.append(f"{cat}: expected {exp}, got {len(faqs)}")
        questions = [f[0] for f in faqs]
        if len(questions) != len(set(questions)):
            rec_err.append(f"{cat}: duplicate questions")
        for i, f in enumerate(faqs):
            short, keywords = f[2], f[4]
            if len(short) > 120:
                rec_err.append(f"{cat}[{i}]: answer_short > 120")
            if len([k for k in keywords.split(",") if k.strip()]) < 3:
                rec_err.append(f"{cat}[{i}]: keywords < 3")
    if rec_err:
        errors["EXTRA_RECORDS"] = rec_err

    hist_err: list[str] = []
    for year, faqs in WC_HISTORY_EXTRAS.items():
        if len(faqs) != 15:
            hist_err.append(f"{year}: expected 15, got {len(faqs)}")
        questions = [f[0] for f in faqs]
        if len(questions) != len(set(questions)):
            hist_err.append(f"{year}: duplicate questions")
    if hist_err:
        errors["WC_HISTORY_EXTRAS"] = hist_err

    return errors


def _count_all() -> int:
    n = 0
    for d in (DISCIPLINE_SEEDS, CULTURE_SEEDS, HEALTH_TRAINING_SEEDS,
              VENUES_TECH_SEEDS, WOMENS_WC_SEEDS, EXTRA_RECORDS):
        n += sum(len(v) for v in d.values())
    n += sum(len(v) for v in WC_HISTORY_EXTRAS.values())
    return n


if __name__ == "__main__":
    total = _count_all()
    errs = validate_seeds()
    print(f"Total FAQs: {total}")
    print(f"DISCIPLINE categories: {len(DISCIPLINE_SEEDS)}")
    print(f"CULTURE categories: {len(CULTURE_SEEDS)}")
    print(f"HEALTH categories: {len(HEALTH_TRAINING_SEEDS)}")
    print(f"VENUES categories: {len(VENUES_TECH_SEEDS)}")
    print(f"WOMENS categories: {len(WOMENS_WC_SEEDS)}")
    print(f"EXTRA_RECORDS categories: {len(EXTRA_RECORDS)}")
    print(f"WC_HISTORY years: {len(WC_HISTORY_EXTRAS)}")
    if errs:
        print("VALIDATION FAILED:")
        for sec, es in errs.items():
            print(f"  {sec}:")
            for e in es[:20]:
                print(f"    - {e}")
            if len(es) > 20:
                print(f"    ... and {len(es) - 20} more")
    else:
        print("VALIDATION PASSED")
